+function shouldPromoteSelectorToCommand(selector: string): boolean {
+  const trimmed = selector.trim();
+  if (!trimmed) {
+    return false;
+  }
+  if (/\s/.test(trimmed)) {
+    return true;
+  }
+  if (/^(?:\.{1,2}\/|~\/|\/)/.test(trimmed)) {
+    return true;
+  }
+  if (/^[A-Za-z]:\\/.test(trimmed) || trimmed.startsWith('\\\\')) {
+    return true;
+  }
+  return false;
+}

